// Build a single Claude payload with all 10 properties.
const items = $input.all().map(i => i.json);
if (!items.length) return [];
const userMsg = JSON.stringify({ properties: items });
return [{ json: { properties: items, userMsg } }];

// Parse Claude response, log cost, prepare insert rows.
const resp = $input.first().json;
const text = resp.content?.[0]?.text || '{}';
const parsed = JSON.parse(text);
const scores = parsed.scores || (parsed.overall_score ? [parsed] : []);
const props = $node['Build Claude payload'].json.properties;
const inputTokens = resp.usage?.input_tokens || 0;
const outputTokens = resp.usage?.output_tokens || 0;
const cost = (inputTokens * 1 + outputTokens * 5) / 1_000_000;
const rows = scores.map((s, i) => ({
  json: {
    listing_id: props[i].listing_id,
    enrichment_id: props[i].enrichment_id,
    overall_score: s.overall_score,
    equity_score: s.equity_score,
    motivation_score: s.motivation_score,
    asset_quality_score: s.asset_quality_score,
    stack_fit_score: s.stack_fit_score,
    tier: s.tier,
    recommended_structure: s.recommended_structure,
    red_flags: s.red_flags || [],
    buyer_pitch_angle: s.buyer_pitch_angle || '',
    claude_input_tokens: inputTokens,
    claude_output_tokens: outputTokens,
    claude_cost_usd: cost
  }
}));
return rows;
